   710→    if (oldVersion < 40 && finalTargetVersion >= 40) {
   711→      // In old dashboards refresh property can be a boolean
   712→      if (typeof this.dashboard.refresh !== 'string') {
   713→        this.dashboard.refresh = '';
   714→      }
   715→    }
   716→
   717→    if (oldVersion < 41 && finalTargetVersion >= 41) {
   718→      // time_options is a legacy property that was not used since grafana version 5
   719→      //  therefore deprecating this property from the schema
