   706→        return panel;
   707→      });
   708→    }
   709→
   710→    if (oldVersion < 40 && finalTargetVersion >= 40) {
   711→      // In old dashboards refresh property can be a boolean
   712→      if (typeof this.dashboard.refresh !== 'string') {
