   728→
   729→    /**
   730→     * ⚠️  WARNING: DO NOT ADD NEW MIGRATIONS HERE ⚠️
   731→     *
   732→     * Schema version 42 is the FINAL version for the v1 dashboard API.
   733→     * This is due to the migration of the legacy dashboards API to the app platform.
   734→     *
   735→     * For panel-specific migrations, implement them as panel migrations in the
   736→     * individual panel plugin migration handlers instead of adding new schema versions.
   737→     */
   738→
   739→    // Apply panel upgrades if any exist
   740→    if (panelUpgrades.length > 0) {
   741→      for (j = 0; j < this.dashboard.panels.length; j++) {
   742→        for (k = 0; k < panelUpgrades.length; k++) {
   743→          this.dashboard.panels[j] = panelUpgrades[k].call(this, this.dashboard.panels[j]);
   744→          const rowPanels = this.dashboard.panels[j].panels;
   745→          if (rowPanels) {
   746→            for (n = 0; n < rowPanels.length; n++) {
   747→              rowPanels[n] = panelUpgrades[k].call(this, rowPanels[n]);
   748→            }
   749→          }
   750→        }
   751→      }
   752→    }
   753→
   754→    // Always update schema version after migrations, regardless of panel upgrades
   755→    // Only update schema version if migrations were actually needed
   756→    if (oldVersion < finalTargetVersion) {
   757→      this.dashboard.schemaVersion = finalTargetVersion;
   758→    }
   759→  }
