  1031→function updateVariablesSyntax(text: string) {
  1032→  const legacyVariableNamesRegex = /(__series_name)|(\$__series_name)|(__value_time)|(__field_name)|(\$__field_name)/g;
  1033→
  1034→  return text.replace(legacyVariableNamesRegex, (match, seriesName, seriesName1, valueTime, fieldName, fieldName1) => {
  1035→    if (seriesName) {
  1036→      return '__series.name';
  1037→    }
  1038→    if (seriesName1) {
  1039→      return '${__series.name}';
  1040→    }
  1041→    if (valueTime) {
  1042→      return '__value.time';
  1043→    }
  1044→    if (fieldName) {
  1045→      return '__field.name';
  1046→    }
  1047→    if (fieldName1) {
  1048→      return '${__field.name}';
  1049→    }
  1050→    return match;
  1051→  });
  1052→}
